#include <cassert>
#include <iostream>

class DynamicArray {
    int* m_data{};
    int m_size{};
    int m_capacity{};

public:
    DynamicArray(int capacity)
        : m_data{ new int[static_cast<std::size_t>(capacity)]{} }
        , m_capacity{ capacity }
    {
    }

    ~DynamicArray() { delete[] m_data; }

    void push_back(int val)
    {
        assert(m_size < m_capacity);
        m_data[m_size++] = val;
    }

    void resize(int newCap)
    {
        int* newData{ new int[static_cast<std::size_t>(newCap)]{} };
        int copyCount{ (m_size < newCap) ? m_size : newCap };
        for (int i{ 0 }; i < copyCount; ++i)
            newData[i] = m_data[i];
        delete[] m_data;
        m_data = newData;
        m_capacity = newCap;
        if (m_size > newCap)
            m_size = newCap;
    }

    int size() const { return m_size; }
    int get(int index) const
    {
        assert(index >= 0 && index < m_size);
        return m_data[index];
    }
};

class FixedArray : public DynamicArray {
public:
    FixedArray(const int* data, int count)
        : DynamicArray{ count }
    {
        for (int i{ 0 }; i < count; ++i)
            DynamicArray::push_back(data[i]);
    }

    void resize(int) = delete;
    void push_back(int) = delete;
};

int main()
{
    int n{};
    std::cin >> n;

    int temp[20]{};
    for (int i{ 0 }; i < n; ++i)
        std::cin >> temp[i];

    FixedArray arr{ temp, n };

    std::cout << "size: " << arr.size() << '\n';
    for (int i{ 0 }; i < arr.size(); ++i)
    {
        if (i > 0)
            std::cout << ' ';
        std::cout << arr.get(i);
    }
    std::cout << '\n';
    std::cout << "fixed: yes" << '\n';

    return 0;
}
